create extension if not exists pgcrypto;
create table public.kol_profiles(id uuid primary key default gen_random_uuid(),slug text unique not null,x_handle text unique not null,display_name text not null,language text not null default 'en',timezone text not null default 'Asia/Singapore',active boolean not null default true,created_at timestamptz not null default now());
create table public.campaign_tasks(id uuid primary key default gen_random_uuid(),kol_id uuid not null references public.kol_profiles(id),wave text not null,stage text not null default 'demo',publish_at timestamptz not null,status text not null,primary_angle text not null,approved_copy text not null,utm_url text not null,requirements jsonb not null default '[]',prohibited_claims jsonb not null default '[]',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.task_assets(id uuid primary key default gen_random_uuid(),task_id uuid not null references public.campaign_tasks(id) on delete cascade,asset_type text not null,file_name text not null,public_url text not null,source_url text,sort_order int not null default 0,active boolean not null default true);
create table public.task_access_tokens(id uuid primary key default gen_random_uuid(),task_id uuid not null references public.campaign_tasks(id) on delete cascade,token_hash text unique not null,expires_at timestamptz not null,revoked_at timestamptz,created_at timestamptz not null default now());
create table public.post_submissions(id uuid primary key default gen_random_uuid(),task_id uuid unique not null references public.campaign_tasks(id),submitted_url text not null,x_username text not null,post_id text unique not null,submitted_at timestamptz not null default now(),verification_status text not null default 'pending',verified_at timestamptz);
create table public.metric_snapshots(id uuid primary key default gen_random_uuid(),submission_id uuid not null references public.post_submissions(id) on delete cascade,snapshot_type text not null check(snapshot_type in('initial','24h','48h_retry','7d','8d_retry','manual')),captured_at timestamptz not null default now(),source text,views bigint,likes bigint,replies bigint,reposts bigint,quotes bigint,bookmarks bigint,raw_payload jsonb,evidence_url text,status text not null,unique(submission_id,snapshot_type,captured_at));
create table public.admin_users(id uuid primary key references auth.users(id) on delete cascade,email text unique not null,role text not null check(role in('admin','editor')),active boolean not null default true);
create table public.audit_logs(id uuid primary key default gen_random_uuid(),actor_id uuid references auth.users(id),action text not null,entity_type text not null,entity_id uuid,metadata jsonb not null default '{}',created_at timestamptz not null default now());
alter table public.kol_profiles enable row level security;alter table public.campaign_tasks enable row level security;alter table public.task_assets enable row level security;alter table public.task_access_tokens enable row level security;alter table public.post_submissions enable row level security;alter table public.metric_snapshots enable row level security;alter table public.admin_users enable row level security;alter table public.audit_logs enable row level security;
create function public.is_portal_staff() returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.admin_users where id=auth.uid() and active and role in('admin','editor'))$$;
revoke all on function public.is_portal_staff() from public;grant execute on function public.is_portal_staff() to authenticated;
create policy staff_kol on public.kol_profiles for all to authenticated using(public.is_portal_staff()) with check(public.is_portal_staff());
create policy staff_tasks on public.campaign_tasks for all to authenticated using(public.is_portal_staff()) with check(public.is_portal_staff());
create policy staff_assets on public.task_assets for all to authenticated using(public.is_portal_staff()) with check(public.is_portal_staff());
create policy staff_tokens on public.task_access_tokens for all to authenticated using(public.is_portal_staff()) with check(public.is_portal_staff());
create policy staff_submissions on public.post_submissions for all to authenticated using(public.is_portal_staff()) with check(public.is_portal_staff());
create policy staff_metrics on public.metric_snapshots for all to authenticated using(public.is_portal_staff()) with check(public.is_portal_staff());
create policy staff_admins on public.admin_users for select to authenticated using(public.is_portal_staff());
create policy staff_audit on public.audit_logs for select to authenticated using(public.is_portal_staff());
-- No anon policies exist. KOL access is exclusively through service-role Edge Functions.
create index task_tokens_hash_idx on public.task_access_tokens(token_hash);create index submissions_post_idx on public.post_submissions(post_id);create index metric_submission_idx on public.metric_snapshots(submission_id,captured_at desc);
